library\(reticulate\)
ps <- import\(''tdata_py.parquet_storage''\)
storage <- ps$ParquetChainsStorage\(\)
cached <- storage$load_chains\(''GDX''\)
if \(!is.null\(cached\) && length\(cached\) > 0\) {
  for \(i in seq_along\(cached\)\) {
    chain <- cached[[i]]
    cat\(''Chain'', i, '': exchange='', chain[[1]], '' tradingClass='', chain[[3]], ''\\n''\)
    strikes <- unlist\(chain[[6]]\)
    cat\(''  Strikes count:'', length\(strikes\), ''\\n''\)
    near_100 <- strikes[strikes >= 90 & strikes <= 120]
    cat\(''  Strikes 90-120:'', paste\(sort\(near_100\), collapse='', ''\), ''\\n\\n''\)
  }
} else {
  cat\(''No cached chains found for GDX\\n''\)
}
")
